import React, { useState } from 'react';
import axios from 'axios';

export default function Register() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [dob, setDob] = useState('');
  const [message, setMessage] = useState('');

  const handleRegister = async (e) => {
    e.preventDefault();
    try {
      const registerResponse = await axios.post('http://localhost:5000/auth/register', {
        username,
        password,
        role: 'Employee', // Automatically set role to Employee
      });
      
      const userId = registerResponse.data.user_id;
      const employeeResponse = await axios.post('http://localhost:5000/employees/create', {
        user_id: userId,
        name: username,
        dob,
      });
      
      setMessage(`Registration successful! Employee Name: ${employeeResponse.data.name}, DOB: ${employeeResponse.data.dob}`);
    } catch (error) {
      setMessage('Registration failed. Please try again.');
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gray-100">
      <div className="bg-white p-6 rounded-lg shadow-lg w-96">
        <h2 className="text-2xl font-bold mb-4 text-center">Register</h2>
        {message && <p className="text-center text-red-500">{message}</p>}
        <form onSubmit={handleRegister} className="space-y-4">
          <div>
            <label className="block text-gray-700">Username</label>
            <input 
              type="text" 
              className="w-full px-3 py-2 border rounded-lg" 
              value={username} 
              onChange={(e) => setUsername(e.target.value)} 
              required 
            />
          </div>
          <div>
            <label className="block text-gray-700">Password</label>
            <input 
              type="password" 
              className="w-full px-3 py-2 border rounded-lg" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              required 
            />
          </div>
          <div>
            <label className="block text-gray-700">Date of Birth</label>
            <input 
              type="date" 
              className="w-full px-3 py-2 border rounded-lg" 
              value={dob} 
              onChange={(e) => setDob(e.target.value)} 
              required 
            />
          </div>
          <button 
            type="submit" 
            className="w-full bg-blue-500 text-white py-2 rounded-lg hover:bg-blue-600">
            Register
          </button>
        </form>
      </div>
    </div>
  );
}
